+/** Returns false when a dependency is missing, otherwise evaluates its data. */
+export function evaluatePredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const ctx = world[$internal];
+    const eid = getEntityId(entity);
+    const values: unknown[] = [];
+
+    for (const trait of predicate.traits) {
+        const instance = getTraitInstance(ctx.traitInstances, trait);
+        if (!instance || !(ctx.entityMasks[instance.generationId][eid] & instance.bitflag)) return false;
+        values.push(trait[$internal].get(eid, instance.store));
+    }
+
+    return predicate.predicate(values as never);
+}
